import { motion } from 'framer-motion';

const faqs = [
  {
    question: 'What investment strategies does Ardhana Capital use?',
    answer:
      'We combine data-driven analytics, active risk management, and disciplined portfolio construction to target consistent, long-term growth while protecting capital.',
  },
  {
    question: 'How do I get started with your services?',
    answer:
      'Visit the Contact page to book a consultation. Our team will review your goals and recommend the best portfolio plan for your needs.',
  },
  {
    question: 'How is performance reported?',
    answer:
      'We provide transparent quarterly performance reports with clear metrics, risk analysis, and commentary on market conditions.',
  },
  {
    question: 'What is your approach to risk management?',
    answer:
      'Risk mitigation is central to our process. We use diversification, volatility monitoring, and active allocation adjustments to manage downside exposure.',
  },
  {
    question: 'Do you offer educational resources?',
    answer:
      'Yes. Our Education page provides market insights, investment fundamentals, and resources designed to help clients make informed decisions.',
  },
];

export const FAQ = () => {
  return (
    <div className="min-h-screen pt-28 pb-24 bg-[#020617] text-white">
      <div className="container mx-auto px-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center max-w-3xl mx-auto pb-12"
        >
          <span className="text-sm uppercase tracking-[0.3em] text-[#A67D32]/80">
            Frequently Asked Questions
          </span>
          <h1 className="mt-6 text-4xl md:text-5xl font-bold text-white">
            Answers to the questions clients ask most.
          </h1>
          <p className="mt-4 text-base text-white/70">
            Learn how Ardhana Capital manages portfolios, measures performance, and supports investors with clarity and confidence.
          </p>
        </motion.div>

        <div className="grid gap-6 md:grid-cols-2">
          {faqs.map((item, index) => (
            <motion.div
              key={item.question}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.08 }}
              className="rounded-3xl border border-white/10 bg-[#0D1320]/80 p-8 shadow-xl shadow-[#020617]/20"
            >
              <h2 className="text-xl font-semibold text-white">
                {item.question}
              </h2>
              <p className="mt-4 text-sm leading-7 text-white/70">
                {item.answer}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
};
